#!/usr/bin/env python3
"""Block `pnpm test` (interactive vitest watcher); steer to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    if tool != "Bash":
        return 0
    cmd = inp.get("command", "")
    stripped = cmd.strip()
    triggers = stripped == "pnpm test" or stripped.startswith("pnpm test ")
    if triggers and "test:ci" not in cmd:
        print(
            "BLOCKING: `pnpm test` opens an interactive vitest watcher and will time out "
            "(observed 3x in telemetry). Use `pnpm test:ci` instead. Do not retry the watcher form.",
            file=sys.stderr,
        )
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Run `pnpm lint` before `git commit`; block on lint failure per CLAUDE.md."""
import json, os, re, subprocess, sys

GIT_COMMIT = re.compile(r"\bgit\s+commit(\s|$)")

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    if tool != "Bash":
        return 0
    cmd = inp.get("command", "")
    if not GIT_COMMIT.search(cmd):
        return 0
    cwd = os.environ.get("CLAUDE_PROJECT_DIR") or ev.get("cwd") or "."
    try:
        r = subprocess.run(
            ["pnpm", "lint"],
            capture_output=True, text=True, timeout=60, cwd=cwd,
        )
    except Exception as e:
        print(
            f"BLOCKING: could not run `pnpm lint` ({e}). Run it manually, fix any errors, "
            "then retry the commit. Do not stop.",
            file=sys.stderr,
        )
        return 2
    if r.returncode != 0:
        print(
            "BLOCKING: `pnpm lint` failed — CLAUDE.md requires lint before committing. "
            "Fix each error, then retry the commit. Do not stop.",
            file=sys.stderr,
        )
        tail = (r.stdout + r.stderr).splitlines()[-30:]
        for line in tail:
            print(line, file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block bare `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    if ev.get("tool_name") != "Bash":
        return 0

    inp = ev.get("tool_input") or {}
    cmd = inp.get("command", "")
    parts = cmd.strip().split()

    if len(parts) >= 2 and parts[0] == "pnpm" and parts[1] == "test":
        print(
            "Use `pnpm test:ci` instead. CLAUDE.md specifies `pnpm test:ci` as the "
            "non-interactive test runner; bare `pnpm test` opens a watcher that won't return.",
            file=sys.stderr,
        )
        return 2

    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block Python Edit/Write/MultiEdit calls that introduce a self-recursive
function with no visible depth bound. Closes the failure mode that crashed
walk_tree (iterative -> recursive refactor; RecursionError on 2000 leaves)."""
import json, re, sys

DEF_RE = re.compile(r"(?m)^\s*(?:async\s+)?def\s+([A-Za-z_]\w*)\s*\(")
GUARD_TOKENS = (
    "setrecursionlimit", "max_depth", "depth_limit", "MAX_DEPTH",
    "if depth", "iterative", "worklist", "stack.pop", "stack.append",
)

def find_self_recursive(text):
    hits = []
    for m in DEF_RE.finditer(text):
        name = m.group(1)
        rest = text[m.end():]
        if re.search(rf"\b{re.escape(name)}\s*\(", rest):
            if not any(tok in rest for tok in GUARD_TOKENS):
                hits.append(name)
    return hits

def payload_for(tool, inp):
    fp = inp.get("file_path", "")
    if not fp.endswith(".py"):
        return ""
    if tool == "Write":
        return inp.get("content", "") or ""
    if tool == "Edit":
        return inp.get("new_string", "") or ""
    if tool == "MultiEdit":
        return "\n".join((e.get("new_string", "") or "") for e in (inp.get("edits") or []))
    return ""

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    if tool not in ("Write", "Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    payload = payload_for(tool, inp)
    if not payload:
        return 0
    hits = find_self_recursive(payload)
    if not hits:
        return 0
    names = ", ".join("`{}`".format(h) for h in hits)
    print(
        "BLOCKING: this edit introduces a self-recursive Python function ({}) "
        "with no visible depth bound. Python's default recursion limit is ~1000 "
        "and this exact pattern previously crashed `walk_tree` on a 2000-leaf tree."
        .format(names),
        file=sys.stderr,
    )
    print(
        "REQUIRED FOLLOW-UP: rewrite using an explicit worklist (iterative) OR "
        "add an explicit depth bound. Do not retry the same recursive shape. Do not ask.",
        file=sys.stderr,
    )
    return 2

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/Write/MultiEdit on a *.py file, run `ruff format` (auto-fix
formatting drift) and surface any remaining `ruff check` issues via stderr."""
import json
import os
import subprocess
import sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool not in ("Edit", "Write", "MultiEdit"):
        return 0

    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "")
    if not path.endswith(".py"):
        return 0
    if not os.path.exists(path):
        return 0

    try:
        subprocess.run(
            ["ruff", "format", path],
            capture_output=True, text=True, timeout=10,
        )
    except Exception:
        return 0

    try:
        r = subprocess.run(
            ["ruff", "check", path],
            capture_output=True, text=True, timeout=10,
        )
    except Exception:
        return 0

    if r.returncode != 0:
        out = (r.stdout + r.stderr).strip()
        print(
            f"REQUIRED FOLLOW-UP: `ruff check {path}` reported issues. "
            "Fix each, then proceed. Do not stop. Do not ask.",
            file=sys.stderr,
        )
        if out:
            print(out[:2000], file=sys.stderr)
        return 2

    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit touches an exported-identifier definition, grep the
codebase for references (old name, renamed name, and old literal value when an
exported string-constant changes value) and feed the list back so renames
don't leave stale callers behind."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)
EXPORT_STR = re.compile(
    r"export\s+const\s+(\w+)\s*=\s*['\"`]([^'\"`]+)['\"`]"
)

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    targets = set()
    for e in edits:
        old_s, new_s = e.get("old_string", ""), e.get("new_string", "")
        om, nm = EXPORT_DEF.search(old_s), EXPORT_DEF.search(new_s)
        if om:
            targets.add(om.group(1))
            if nm and nm.group(1) != om.group(1):
                targets.add(nm.group(1))
        ov, nv = EXPORT_STR.search(old_s), EXPORT_STR.search(new_s)
        if ov and nv and ov.group(2) != nv.group(2):
            targets.add(ov.group(2))

    if not targets:
        return 0

    findings = []
    for needle in targets:
        try:
            r = subprocess.run(
                ["grep", "-rn",
                 "--include=*.ts", "--include=*.tsx", "--include=*.js", "--include=*.jsx",
                 "--exclude-dir=node_modules", "--exclude-dir=dist", "--exclude-dir=build",
                 needle, "."],
                capture_output=True, text=True, timeout=5,
                cwd=ev.get("cwd") or ".",
            )
            hits = [l for l in r.stdout.splitlines() if l][:20]
            if hits:
                findings.append((needle, hits))
        except Exception:
            pass

    if not findings:
        return 0

    total = sum(len(h) for _, h in findings)
    print(f"BLOCKING: exported-identifier edit detected. {total} reference(s) remain:", file=sys.stderr)
    for needle, hits in findings:
        print(f"-- `{needle}` --", file=sys.stderr)
        for h in hits:
            print(f"  {h}", file=sys.stderr)
    print("Update each reference, then proceed. Do not stop. Do not ask.", file=sys.stderr)
    return 2

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block `git push --force` (and variants) targeting main/master."""
import json, re, sys

FORCE_RE = re.compile(
    r"\bgit\s+push\b.*(?:--force\b|--force-with-lease\b|--force-if-includes\b|\s-f\b)"
)
MAIN_RE = re.compile(r"(?:\s|/)(?:main|master)(?:\s|$)")

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not FORCE_RE.search(cmd):
        return 0
    if not MAIN_RE.search(cmd):
        return 0
    print(
        "BLOCKING: refusing to force-push to main/master. The project requires human involvement for pushes; force-push rewrites shared history. The user must run this command manually if it is intentional.",
        file=sys.stderr,
    )
    return 2

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Enforce short imperative subject line on `git commit -m` messages."""
import json, shlex, sys

NARRATIVE_STARTS = (
    "this commit", "this change", "this pr", "this patch",
    "it ", "we ", "the goal", "the purpose", "in order to",
)
MAX_SUBJECT = 72


def extract_messages(cmd):
    try:
        tokens = shlex.split(cmd)
    except ValueError:
        return []
    msgs, i = [], 0
    while i < len(tokens):
        t = tokens[i]
        if t in ("-m", "--message") and i + 1 < len(tokens):
            msgs.append(tokens[i + 1]); i += 2; continue
        if t.startswith("--message="):
            msgs.append(t.split("=", 1)[1])
        elif t.startswith("-m") and len(t) > 2:
            msgs.append(t[2:])
        i += 1
    return msgs


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if "git commit" not in cmd:
        return 0
    for m in extract_messages(cmd):
        subject = m.split("\n", 1)[0].strip()
        problems = []
        if len(subject) > MAX_SUBJECT:
            problems.append(f"subject is {len(subject)} chars (max {MAX_SUBJECT})")
        low = subject.lower()
        if any(low.startswith(s) for s in NARRATIVE_STARTS):
            problems.append("subject opens with narrative phrasing, not an imperative verb")
        if problems:
            print("BLOCKING: commit subject violates team convention "
                  "(short imperative line, e.g. 'Refactor auth: extract token validation').",
                  file=sys.stderr)
            for p in problems:
                print(f"  - {p}", file=sys.stderr)
            print(f"  subject: {subject!r}", file=sys.stderr)
            print("Rewrite with a short imperative subject (~50 chars), then re-run.", file=sys.stderr)
            return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

