#!/usr/bin/env python3
"""After Write/Edit/MultiEdit on a .py file, run pyflakes and surface findings.

Catches the failure mode where Claude writes code referencing identifiers that
don't exist in scope (e.g. `grand_total = total + tax` when only `subtotal`
is defined). Pyflakes flags undefined names, unused imports, etc.
"""
import json, os, subprocess, sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit", "Write"):
        return 0
    inp = ev.get("tool_input") or {}
    path = inp.get("file_path", "")
    if not path.endswith(".py") or not os.path.isfile(path):
        return 0

    try:
        r = subprocess.run(
            ["python3", "-m", "pyflakes", path],
            capture_output=True, text=True, timeout=10,
        )
    except Exception:
        return 0  # never break Claude Code if pyflakes can't run

    output = (r.stdout + r.stderr).strip()
    if "No module named pyflakes" in output:
        return 0  # pyflakes not installed; silently skip
    if r.returncode == 0 or not output:
        return 0

    print(f"BLOCKING: pyflakes flagged issues in {path}:", file=sys.stderr)
    print(output, file=sys.stderr)
    print("Fix each, then continue. Do not stop. Do not ask.", file=sys.stderr)
    return 2


if __name__ == "__main__":
    sys.exit(main())
